-      std::vector<std::pair<int32_t, int32_t>> numBytesAndAlignmentPerSmemChunk;
-      std::vector<bool> firstChunkReuseSmem;
-      // Buffer names for inspection purposes.
-      std::vector<std::string> smemChunkNames;
