-    }
-    ss << std::endl;
-
-    ss << "Stride: ";
-    for (int ii = 0; ii < dim - 1; ++ii) {
-      ss << stridesInBytes[ii] << " ";
-    }
-    ss << std::endl;
-
-    ss << "tileShapes: ";
-    for (int ii = 0; ii < dim; ++ii) {
-      ss << boxDim[ii] << " ";
-    }
-    ss << std::endl;
-
-    ss << "tileStrides: ";
