-// Is a given data type an integer type?
-inline bool dtypeIsInt(Dtype dtype) {
-  constexpr uint32_t kMask = 0x1u << 16;
-  return (dtype != Dtype::Bool) && (0 != (static_cast<uint32_t>(dtype) & kMask));
-}
-
-////////////////////////////////////////////////////////////////////////////////////////////////////
