-    case Dtype::Int8:
-      return "Int8";
-    case Dtype::Int32:
-      return "Int32";
-    case Dtype::Int64:
-      return "Int64";
-    case Dtype::MxE4m3:
-      return "MxE4m3";
-    case Dtype::MxE2m1:
-      return "MxE2m1";
-    case Dtype::MxInt4:
-      return "MxInt4";
-    case Dtype::UE8m0:
-      return "UE8m0";
-    case Dtype::UInt8:
-      return "UInt8";
-    case Dtype::UInt16:
-      return "UInt16";
-    case Dtype::UInt32:
-      return "UInt32";
-    case Dtype::UInt64:
-      return "UInt64";
-    case Dtype::UInt128:
