-inline Dtype dtypeGetBlockSfType(Dtype dtype) {
-  switch (dtype) {
-    case Dtype::E2m1:
-      return Dtype::E4m3;
-    case Dtype::MxE2m1:
-    case Dtype::MxE4m3:
-      return Dtype::UE8m0;
